mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM project
    WHERE id = #{projectId}
      AND deleted_at IS NULL
)

SELECT EXISTS (
    SELECT 1
    FROM project_member
    WHERE project_id = #{projectId}
      AND user_id = #{userId}
)

SELECT w.id
FROM workspace w
WHERE w.slug = #{slug}
  AND w.created_by = #{userId}
LIMIT 1
